use rusqlite::Connection;
use std::path::Path;
use cowclaw_swarm::budget::Tier;

pub struct RuleB;

const MIN_COUNT: i64 = 3;
const TEMPLATE: &str = "---
name: {name}
description: Auto-generated skill from repeated tool sequence
trigger_hints: {canonical_first_line}
tier: default
---
# Steps

{steps}

*Auto-generated by Rule B (cowclaw-promoter)*
";

impl RuleB {
    pub fn run(conn: &Connection, skills_dir: &Path) -> cowclaw_swarm::Result<usize> {
        let mut stmt = conn.prepare(
            "SELECT fingerprint, canonical FROM tool_sequences WHERE count >= ?1 AND promoted_skill IS NULL",
        )?;
        let rows: Vec<(String, String)> = stmt
            .query_map([MIN_COUNT], |r| Ok((r.get(0)?, r.get(1)?)))?
            .collect::<rusqlite::Result<_>>()?;

        let mut count = 0;
        for (fp, canonical) in rows {
            let name = format!("auto-{}", fp);
            let first_line = canonical.lines().next().unwrap_or("").trim().to_string();
            let content = TEMPLATE
                .replace("{name}", &name)
                .replace("{canonical_first_line}", &first_line)
                .replace("{steps}", &canonical);

            // Check size constraint
            let line_count = content.lines().count();
            if line_count > Tier::Default.max_lines() {
                tracing::error!(
                    "Rule B: generated skill '{}' exceeds Default tier ({} > {}), skipping",
                    name,
                    line_count,
                    Tier::Default.max_lines()
                );
                continue;
            }

            let skill_dir = skills_dir.join(&name);
            std::fs::create_dir_all(&skill_dir)?;
            std::fs::write(skill_dir.join("SKILL.md"), &content)?;
            count += 1;
        }
        Ok(count)
    }
}
